package com.wjx871.population.floating;import com.wjx871.population.audit.*;import java.util.List;import lombok.RequiredArgsConstructor;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.*;
@Service @RequiredArgsConstructor public class ResidencePermitExpiryService {private final FloatingResidenceMapper mapper;private final ResidencePermitDatePolicy dates;private final ResidencePermitExpiryWorker worker;@Scheduled(cron="${residence-permit.expiry-cron:0 0 2 * * *}")public void scheduled(){runNow();}public int runNow(){List<ResidencePermit> permits=mapper.expiredCandidates(dates.today());permits.forEach(p->worker.expirePermit(p.getPermitId()));List<FloatingPopulation> registrations=mapper.expiredFloatingCandidates(dates.today());registrations.forEach(f->worker.expireFloating(f.getFloatingId()));return permits.size()+registrations.size();}}
@Service @RequiredArgsConstructor class ResidencePermitExpiryWorker {private final FloatingResidenceMapper mapper;private final FloatingResidenceTransactionHook hook;private final OperationLogMapper audit;
@Transactional(propagation=Propagation.REQUIRES_NEW)public void expirePermit(Long id){ResidencePermit p=mapper.lockPermit(id).orElse(null);if(p==null||!"ACTIVE".equals(p.getStatus()))return;if(mapper.expirePermit(id,p.getVersion())==0)return;hook.afterPermitExpire();log(p,"EXPIRE","ACTIVE","EXPIRED","到期自动失效");system("RESIDENCE_PERMIT_EXPIRE");}
@Transactional(propagation=Propagation.REQUIRES_NEW)public void expireFloating(Long id){FloatingPopulation f=mapper.lockFloating(id).orElse(null);if(f==null||!"ACTIVE".equals(f.getStatus()))return;if(mapper.closeFloating(id,"EXPIRED","PLANNED_LEAVE_EXPIRED",f.getVersion())==0)return;mapper.findActivePermitByFloating(id).ifPresent(p->{if(mapper.expirePermit(p.getPermitId(),p.getVersion())>0)log(p,"REGISTRATION_CLOSED","ACTIVE","EXPIRED","流动登记到期");});system("FLOATING_REGISTRATION_EXPIRE");}
private void log(ResidencePermit p,String action,String from,String to,String reason){ResidencePermitLog l=new ResidencePermitLog();l.setPermitId(p.getPermitId());l.setAction(action);l.setFromStatus(from);l.setToStatus(to);l.setOldValidUntil(p.getValidUntil());l.setNewValidUntil(p.getValidUntil());l.setReason(reason);mapper.insertPermitLog(l);}private void system(String type){audit.insert(OperationLog.builder().operationType(type).moduleName("FLOATING_RESIDENCE").operationResult("SUCCESS").detail(type).build());}}
